const prices=$input.all().map(i=>i.json);if(prices.length<50)return [{json:{skip:true}}];
const closes=prices.map(p=>p.close_price).reverse();const volumes=prices.map(p=>p.volume).reverse();
const ticker=prices[0].ticker||'';const today=prices[0].price_date;
const sma=(a,p)=>{if(a.length<p)return null;return a.slice(a.length-p).reduce((s,v)=>s+v,0)/p;};
const calcRSI=(c,p=14)=>{if(c.length<p+1)return null;let g=0,l=0;for(let i=c.length-p;i<c.length;i++){const ch=c[i]-c[i-1];if(ch>0)g+=ch;else l-=ch;}return 100-(100/(1+g/(l||1)));};
const ema=(a,p)=>{const k=2/(p+1);let e=a[0];for(let i=1;i<a.length;i++)e=a[i]*k+e*(1-k);return e;};
const s50=sma(closes,50),s200=sma(closes,200),rsi=calcRSI(closes,14),macd=ema(closes,12)-ema(closes,26),bb=sma(closes,20),vs=sma(volumes,20),cp=closes[closes.length-1];
const rs=rsi>70?'overbought':rsi<30?'oversold':'neutral';const tr=cp>s50&&s50>s200?'bullish':cp<s50&&s50<s200?'bearish':'neutral';
return [{indicator_name:'RSI_14',value:rsi,signal:rs},{indicator_name:'SMA_50',value:s50,signal:cp>s50?'above':'below'},{indicator_name:'SMA_200',value:s200,signal:cp>s200?'above':'below'},{indicator_name:'MACD',value:macd,signal:macd>0?'bullish':'bearish'},{indicator_name:'BB_MIDDLE',value:bb,signal:'reference'},{indicator_name:'VOL_SMA_20',value:vs,signal:volumes[volumes.length-1]>vs?'above_avg':'below_avg'},{indicator_name:'TREND',value:cp,signal:tr}].map(r=>({json:{ticker,indicator_date:today,...r}}));
